###This code is for analyzing the SH-SY5Y microarray data using WGCNA (weighted gene coexpression network analysis) using R ###Paste the following functions into R PickSoftThreshold=function(datExpr1,RsquaredCut=0.85, powervector=c(seq(1,10,by=1),seq(12,20,by=2)),removeFirst=FALSE,no.breaks=10) { no.genes &lt;- dim(datExpr1)[2] no.genes &lt;- dim(datExpr1)[2] no.samples= dim(datExpr1)[1] colname1=c(&#34;Power&#34;, &#34;scale law R2&#34; ,&#34;slope&#34;, &#34;truncated R2&#34;,&#34;mean(k)&#34;,&#34;median(k)&#34;,&#34;max(k)&#34;) datout=data.frame(matrix(666,nrow=length(powervector),ncol=length(colname1) )) names(datout)=colname1 datout[,1]=powervector if(exists(&#34;fun1&#34;)) rm(fun1) fun1=function(x) { corx=abs(cor(x,datExpr1,use=&#34;p&#34;)) out1=rep(NA, length(powervector) ) for (j in c(1:length(powervector))) {out1[j]=sum(corx^powervector[j])} out1 } # end of fun1 datk=t(apply(datExpr1,2,fun1)) for (i in c(1:length(powervector) ) ){ nolinkshelp &lt;- datk[,i]-1 cut2=cut(nolinkshelp,no.breaks) binned.k=tapply(nolinkshelp,cut2,mean) freq1=as.vector(tapply(nolinkshelp,cut2,length)/length(nolinkshelp)) The following code corrects for missing values etc breaks1=seq(from=min(nolinkshelp),to=max(nolinkshelp),length=no.breaks+1) hist1=hist(nolinkshelp,breaks=breaks1,equidist=F,plot=FALSE,right=TRUE) binned.k2=hist1$mids binned.k=ifelse(is.na(binned.k),binned.k2,binned.k) binned.k=ifelse(binned.k==0,binned.k2,binned.k) freq1=ifelse(is.na(freq1),0,freq1) xx= as.vector(log10(binned.k)) if(removeFirst) {freq1=freq1[-1]; xx=xx[-1]} plot(xx,log10(freq1+.000000001),xlab=&#34;log10(k)&#34;,ylab=&#34;log10(p(k))&#34; ) lm1= lm(as.numeric(log10(freq1+.000000001))~ xx ) lm2=lm(as.numeric(log10(freq1+.000000001))~ xx+I(10^xx) ) datout[i,2]=summary(lm1)$adj.r.squared datout[i,3]=summary(lm1)$coefficients[2,1] datout[i,4]=summary(lm2)$adj.r.squared datout[i,5]=mean(nolinkshelp) datout[i,6]= median(nolinkshelp) datout[i,7]= max(nolinkshelp) } datout=signif(datout,3) print(data.frame(datout)); the cut-off is chosen as smallest cut with R^2&gt;RsquaredCut indcut=NA indcut=ifelse(sum(ind1)&gt;0,min(c(1:length(ind1))[ind1]),indcut) this estimates the power value that should be used. Don&#39;t trust it. You need to consider slope and mean connectivity as well! power.estimate=powervector[indcut][1] list(power.estimate, data.frame(datout)); } TOMdist1=function(adjmat1, maxADJ=FALSE) { diag(adjmat1)=0; adjmat1[is.na(adjmat1)]=0; maxh1=max(as.dist(adjmat1) ); minh1=min(as.dist(adjmat1) ); if (maxh1&gt;1 | minh1 &lt; 0 ) {print(paste(&#34;ERROR: the adjacency matrix contains entries that are larger than 1 or smaller than 0!!!, max=&#34;,maxh1,&#34;, min=&#34;,minh1)) } else { if ( max(c(as.dist(abs(adjmat1-t(adjmat1)))))&gt;0 ) {print(&#34;ERROR: non-symmetric adjacency matrix!!!&#34;) } else { kk=apply(adjmat1,2,sum) maxADJconst=1 if (maxADJ==TRUE) maxADJconst=max(c(as.dist(adjmat1 ))) Dhelp1=matrix(kk,ncol=length(kk),nrow=length(kk)) denomTOM= pmin(as.dist(Dhelp1),as.dist(t(Dhelp1))) +as.dist(maxADJconst-adjmat1); gc();gc(); numTOM=as.dist(adjmat1 %*% adjmat1 +adjmat1); #TOMmatrix=numTOM/denomTOM this turns the TOM matrix into a dissimilarity out1=1-as.matrix(numTOM/denomTOM) diag(out1)=1 out1 } } } makeNetwork = function(dat,beta,signed=0){ if(signed==0){ a = abs(cor(dat,use=&#34;p&#34;)^beta) t = TOMdist1(a) return(hclust(as.dist(t),method=&#34;av&#34;)) }else{ a = cor(dat,use=&#34;p&#34;) b = a &lt; 0 a[b] = 0 a = a^beta t = TOMdist1(a) return(hclust(as.dist(t),method=&#34;av&#34;)) } } cutreeDynamic = function(hierclust, maxTreeHeight=1, deepSplit=TRUE, minModuleSize=50, minAttachModuleSize=100, nameallmodules=FALSE, useblackwhite=FALSE) { if(maxTreeHeight &gt;=1){ staticCutCluster = cutTreeStatic(hiercluster=hierclust, heightcutoff=0.99, minsize1=minModuleSize) }else{ staticCutCluster = cutTreeStatic(hiercluster=hierclust, heightcutoff=maxTreeHeight, minsize1=minModuleSize) } #get tree height for every singleton #node_index tree_height demdroHeiAll= rbind( cbind(hierclust$merge[,1], hierclust$height), cbind(hierclust$merge[,2], hierclust$height) ) #singletons will stand at the front of the list myorder = order(demdroHeiAll[,1]) #get # of singletons no.singletons = length(hierclust$order) demdroHeiAll.sort = demdroHeiAll[myorder, ] demdroHei.sort = demdroHeiAll.sort[c(1:no.singletons), ] demdroHei = demdroHei.sort[seq(no.singletons, 1, by=-1), ] demdroHei[,1] = -demdroHei[,1] combine with prelimilary cluster-cutoff results demdroHei = cbind(demdroHei, as.integer(staticCutCluster)) re-order the order based on the dendrogram order hierclust$order demdroHei.order = demdroHei[hierclust$order, ] static.clupos = locateCluster(demdroHei.order[, 3]) if (is.null(static.clupos) ){ module.assign = rep(0, no.singletons) colcode.reduced = assignModuleColor(module.assign, minsize1=minModuleSize, anameallmodules=nameallmodules, auseblackwhite=useblackwhite) return ( colcode.reduced ) } static.no = dim(static.clupos)1 static.clupos2 = static.clupos static.no2 = static.no #split individual cluster if there are sub clusters embedded mcycle=1 while(1==1){ clupos = NULL for (i in c(1:static.no)){ mydemdroHei.order = demdroHei.order[ c(static.clupos[i,1]:static.clupos[i,2]), ] #index to [1, clusterSize] mydemdroHei.order[, 1] = mydemdroHei.order[, 1] - static.clupos[i, 1] + 1 #cat(&#34;Cycle &#34;, as.character(mcycle), &#34;cluster (&#34;, static.clupos[i,1], static.clupos[i,2], &#34;)
&#34;) #cat(&#34;i=&#34;, as.character(i), &#34;
&#34;) iclupos = processInvididualCluster(mydemdroHei.order, cminModuleSize = minModuleSize, cminAttachModuleSize = minAttachModuleSize) iclupos[,1] = iclupos[,1] + static.clupos[i, 1] -1 #recover the original index iclupos[,2] = iclupos[,2] + static.clupos[i, 1] -1 clupos = rbind(clupos, iclupos) #put in the final output buffer } if(deepSplit==FALSE){ break } if(dim(clupos)1 != static.no) { static.clupos = clupos static.no = dim(static.clupos)1 }else{ break } mcycle = mcycle + 1 #static.clupos } final.cnt = dim(clupos)1 #assign colors for modules module.assign = rep(0, no.singletons) module.cnt=1 for (i in c(1:final.cnt )) { sdx = clupos[i, 1] #module start point edx = clupos[i, 2] #module end point module.size = edx - sdx +1 if(module.size &lt;minModuleSize){ next } #assign module lable module.assign[sdx:edx] = rep(module.cnt, module.size) #update module label for the next module module.cnt = module.cnt + 1 } colcode.reduced.order = assignModuleColor(module.assign, minsize1=minModuleSize, anameallmodules=nameallmodules, auseblackwhite=useblackwhite) recov.order = order( demdroHei.order[,1]) colcode.reduced = colcode.reduced.order[recov.order] if(1==2){ aveheight = averageSequence(demdroHei.order[,2], 2) procHei = demdroHei.order[,2]-mean(demdroHei.order[,2]) par(mfrow=c(3,1), mar=c(0,0,0,0) ) plot(h1row, labels=F, xlab=&#34;&#34;,ylab=&#34;&#34;,main=&#34;&#34;,sub=&#34;&#34;,axes = F) barplot(procHei, col= &#34;black&#34;, space=0, border=F,main=&#34;&#34;, axes = F, axisnames = F) barplot(height=rep(1, length(colcode.reduced)), col= as.character(colcode.reduced[h1row$order]), space=0, border=F,main=&#34;&#34;, axes = F, axisnames = F) par(mfrow=c(1,1), mar=c(5, 4, 4, 2) + 0.1) } colcode.reduced } cutTreeStatic = function(hiercluster,heightcutoff=0.99, minsize1=50) { here we define modules by using a height cut-off for the branches labelpred= cutree(hiercluster,h=heightcutoff) sort1=-sort(-table(labelpred)) sort1 modulename= as.numeric(names(sort1)) modulebranch= sort1 &gt;= minsize1 no.modules=sum(modulebranch) colorhelp = rep(-1, length(labelpred) ) if ( no.modules==0){ print(&#34;No module detected&#34;) } else{ for (i in c(1:no.modules)) { colorhelp=ifelse(labelpred==modulename[i],i ,colorhelp) } } colorhelp } locateCluster = function(clusterlabels) { no.nodes = length(clusterlabels) clusterlabels.shift = c(clusterlabels1, c(clusterlabels[1:(no.nodes-1)]) ) #a non-zero point is the start point of a cluster and it previous point is the end point of the previous cluster label.diff = abs(clusterlabels - clusterlabels.shift) #process the first and last positions as start/end points if they belong to a cluster instead of no cluster &#34;-1&#34; if(clusterlabels1 &gt;0) {label.diff1=1} if(clusterlabels[no.nodes]&gt;0) {label.diff[no.nodes]=1} flagpoints.bool = label.diff &gt; 0 if( sum(flagpoints.bool) ==0){ return(NULL) } flagpoints = c(1:no.nodes)[flagpoints.bool] no.points = length(flagpoints) myclupos=NULL for(i in c(1:(no.points-1)) ){ idx = flagpoints[i] if(clusterlabels[idx]&gt;0){ myclupos = rbind(myclupos, c(idx, flagpoints[i+1]-1) ) } } myclupos } processInvididualCluster = function(clusterDemdroHei, cminModuleSize=50, cminAttachModuleSize=100, minTailRunlength=12, useMean=0){ #for debug: use all genes #clusterDemdroHei =demdroHei.order no.cnodes = dim(clusterDemdroHei)1 cmaxhei = max(clusterDemdroHei[, 2]) cminhei = min(clusterDemdroHei[, 2]) cmeanhei = mean(clusterDemdroHei[, 2]) cmidhei = (cmeanhei + cmaxhei)/2.0 cdwnhei = (cmeanhei + cminhei)/2.0 if (useMean==1){ comphei = cmidhei }else if (useMean==-1){ comphei = cdwnhei }else{ #normal case comphei = cmeanhei } compute height diffrence with mean height heidiff = clusterDemdroHei[,2] - comphei heidiff.shift = shiftSequence(heidiff, -1) get cut positions detect the end point of a cluster, whose height should be less than meanhei and the node behind it is the start point of the next cluster which has a height above meanhei cuts.bool = (heidiff&lt;0) &amp; (heidiff.shift &gt; 0) cuts.bool1 = TRUE cuts.bool[no.cnodes] = TRUE if(sum(cuts.bool)==2){ if (useMean==0){ new.clupos=processInvididualCluster(clusterDemdroHei=clusterDemdroHei, cminModuleSize=cminModuleSize, cminAttachModuleSize=cminAttachModuleSize, useMean=1) }else if(useMean==1){ new.clupos=processInvididualCluster(clusterDemdroHei=clusterDemdroHei, cminModuleSize=cminModuleSize, cminAttachModuleSize=cminAttachModuleSize, useMean=-1) }else{ new.clupos = rbind(c(1, no.cnodes)) } return (new.clupos) } #a good candidate cluster-end point should have significant # of ahead nodes with head &lt; meanHei cutindex =c(1:no.cnodes)[cuts.bool] no.cutps = length(cutindex) runlens = rep(999, no.cutps) cuts.bool2 = cuts.bool for(i in c(2:(no.cutps-1)) ){ seq = c( (cutindex[i-1]+1):cutindex[i] ) runlens[i] = runlengthSign(heidiff[seq], leftOrright=-1, mysign=-1) if(runlens[i] &lt; minTailRunlength){ #cat(&#34;run length=&#34;, runlens[i], &#34;
&#34;) cuts.bool2[ cutindex[i] ] = FALSE } } #attach SMALL cluster to the left-side BIG cluster if the small one has smaller mean height cuts.bool3=cuts.bool2 if(sum(cuts.bool2) &gt; 3) { curj = 2 while (1==1){ cutindex2 =c(1:no.cnodes)[cuts.bool2] no.clus = length(cutindex2) -1 if (curj&gt;no.clus){ break } pre.sdx = cutindex2[ curj-1 ]+1 #previous module start point pre.edx = cutindex2[ curj ] #previous module end point pre.module.size = pre.edx - pre.sdx +1 pre.module.hei = mean(clusterDemdroHei[c(pre.sdx:pre.edx) , 2]) cur.sdx = cutindex2[ curj ]+1 #previous module start point cur.edx = cutindex2[ curj+1 ] #previous module end point cur.module.size = cur.edx - cur.sdx +1 cur.module.hei = mean(clusterDemdroHei[c(cur.sdx:cur.edx) , 2]) #merge to the leftside major module, don&#39;t change the current index &#34;curj&#34; #if( (pre.module.size &gt;minAttachModuleSize)&amp;(cur.module.hei&lt;pre.module.hei)&amp;(cur.module.size&lt;minAttachModuleSize) ){ if( (cur.module.hei&lt;pre.module.hei)&amp;(cur.module.size&lt;cminAttachModuleSize) ){ cuts.bool2[ cutindex2[curj] ] = FALSE }else{ #consider next cluster curj = curj + 1 } }#while }#if cutindex2 =c(1:no.cnodes)[cuts.bool2] no.cutps = length(cutindex2) #we don&#39;t want to lose the small cluster at the tail, attch it to the previous big cluster #cat(&#34;Lclu= &#34;, cutindex2[no.cutps]-cutindex2[no.cutps-1]+1, &#34;
&#34;) if(no.cutps &gt; 2){ if( (cutindex2[no.cutps] - cutindex2[no.cutps-1]+1) &lt; cminModuleSize ){ cuts.bool2[ cutindex2[no.cutps-1] ] =FALSE } } if(1==2){ myseqnce = c(2300:3000) cutdisp = ifelse(cuts.bool2==T, &#34;red&#34;,&#34;grey&#34; ) #re-order to the normal one with sequential signleton index par(mfrow=c(3,1), mar=c(0,0,0,0) ) plot(h1row, labels=F, xlab=&#34;&#34;,ylab=&#34;&#34;,main=&#34;&#34;,sub=&#34;&#34;,axes = F) barplot(heidiff[myseqnce], col= &#34;black&#34;, space=0, border=F,main=&#34;&#34;, axes = F, axisnames = F) barplot(height=rep(1, length(cutdisp[myseqnce])), col= as.character(cutdisp[myseqnce]), space=0, border=F,main=&#34;&#34;, axes = F, axisnames = F) par(mfrow=c(1,1), mar=c(5, 4, 4, 2) + 0.1) } cutindex2 = c(1:no.cnodes)[cuts.bool2] cutindex21=cutindex21-1 #the first no.cutps2 = length(cutindex2) if(no.cutps2 &gt; 2){ new.clupos = cbind( cutindex2[c(1:(no.cutps2-1))]+1, cutindex2[c(2:no.cutps2)] ) }else{ new.clupos = cbind( 1, no.cnodes) } if ( dim(new.clupos)1 == 1 ){ if (useMean==0){ new.clupos=processInvididualCluster(clusterDemdroHei=clusterDemdroHei, cminModuleSize=cminModuleSize, cminAttachModuleSize=cminAttachModuleSize, useMean=1) }else if(useMean==1){ new.clupos=processInvididualCluster(clusterDemdroHei=clusterDemdroHei, cminModuleSize=cminModuleSize, cminAttachModuleSize=cminAttachModuleSize, useMean=-1) } } new.clupos } shiftSequence = function(mysequence, delta){ seqlen = length(mysequence) if(delta&gt;0){ finalseq=c(mysequence[1:delta], mysequence[1:(seqlen-delta)]) }else{ posdelta = -delta finalseq=c(mysequence[(posdelta+1):seqlen], mysequence[(seqlen-posdelta+1):seqlen]) } finalseq } runlengthSign = function(mysequence, leftOrright=-1, mysign=-1){ seqlen = length(mysequence) if(leftOrright&lt;0){ pseq = rev(mysequence) }else{ pseq = mysequence } if(mysign&lt;0){ #see where the first POSITIVE number occurs nonezero.bool = (pseq &gt; 0) }else{ #see where the first NEGATIVE number occur nonezero.bool = (pseq &lt; 0) } if( sum(nonezero.bool) &gt; 0){ runlength = min( c(1:seqlen)[nonezero.bool] ) - 1 }else{ runlength = 0 } } assignModuleColor = function(labelpred, minsize1=50, anameallmodules=FALSE, auseblackwhite=FALSE) { here we define modules by using a height cut-off for the branches #labelpred= cutree(hiercluster,h=heightcutoff) #cat(labelpred) #&#34;0&#34;, grey module doesn&#39;t participate color assignment, directly assigned as &#34;grey&#34; labelpredNoZero = labelpred[ labelpred &gt;0 ] sort1=-sort(-table(labelpredNoZero)) sort1 modulename= as.numeric(names(sort1)) modulebranch= sort1 &gt;= minsize1 no.modules=sum(modulebranch) now we assume that there are fewer than 10 modules #colorcode=c#(&#34;turquoise&#34;,&#34;blue&#34;,&#34;brown&#34;,&#34;yellow&#34;,&#34;green&#34;,&#34;red&#34;,&#34;black&#34;,&#34;purple&#34;,&#34;orange&#34;,&#34;pink&#34;, #&#34;greenyellow&#34;,&#34;lightcyan&#34;,&#34;salmon&#34;,&#34;midnightblue&#34;,&#34;lightyellow&#34;,&#34;chartreuse&#34;, &#34;chocolate&#34;,&#34;gold&#34;,&#34;springgreen&#34;,&#34;tan&#34;,&#34;violet&#34;,&#34;plum&#34;,&#34;aliceblue&#34;,&#34;aquamarine&#34;, &#34;azure&#34;,&#34;bisque&#34;,&#34;burlywood&#34;,&#34;coral&#34;,&#34;cornsilk&#34;,&#34;cyan&#34;,&#34;darkorchid&#34;,&#34;deeppink&#34;, &#34;firebrick&#34;,&#34;forestgreen&#34;,&#34;gainsboro&#34;,&#34;wheat&#34;) orderofcolors = order(runif(length(colors()))) colorcode = colors() colorcode = colorcode[orderofcolors] notgrey = substr(colorcode,1,4) &#34;gray&#34; | substr(colorcode,1,4) &#34;grey&#34; colorcode = colorcode[!notgrey] #&#34;grey&#34; means not in any module; colorhelp=rep(&#34;grey&#34;,length(labelpred)) if ( no.modules==0){ print(&#34;No module detected
&#34;) } else{ if ( no.modules &gt; length(colorcode) ){ print(length(colorcode)) print( paste(&#34;Too many modules 
&#34;, as.character(no.modules)) ) } if ( (anameallmodules==FALSE) || (no.modules &lt;=length(colorcode)) ){ labeledModules = min(no.modules, length(colorcode) ) for (i in c(1:labeledModules)) { colorhelp=ifelse(labelpred==modulename[i],colorcode[i],colorhelp) } colorhelp=factor(colorhelp,levels=c(colorcode[1:labeledModules],&#34;grey&#34;)) }else{#nameallmodules==TRUE and no.modules &gt;length(colorcode) maxcolors=length(colorcode) labeledModules = no.modules extracolors=NULL blackwhite=c(&#34;red&#34;, &#34;black&#34;) for(i in c((maxcolors+1):no.modules)){ if(auseblackwhite==FALSE){ icolor=paste(&#34;module&#34;, as.character(i), sep=&#34;&#34;) }else{#use balck white alternatively represent extra colors, for display only #here we use the ordered label to avoid put the same color for two neighboring clusters icolor=blackwhite[1+(as.integer(modulename[i])%%2) ] } extracolors=c(extracolors, icolor) } #combine the true-color code and the extra colorcode into a uniform colorcode for #color assignment allcolorcode=c(colorcode, extracolors) for (i in c(1:labeledModules)) { colorhelp=ifelse(labelpred==modulename[i],allcolorcode[i],colorhelp) } colorhelp=factor(colorhelp,levels=c(allcolorcode[1:labeledModules],&#34;grey&#34;)) } } colorhelp } hclustplot1=function(hier1,couleur,title1=&#34;Colors sorted by hierarchical clustering&#34;) { if (length(hier1$order) != length(couleur) ) { print(&#34;ERROR: length of color vector not compatible with no. of objects in the hierarchical tree&#34;)}; if (length(hier1$order) == length(couleur) ) { barplot(height=rep(1, length(couleur)), col= as.character(couleur[hier1$order]),border=NA, main=title1,space=0, axes=F)} } plotDend=function(clust,colorh){ par(mfrow=c(2,1),mar=c(2,2,2,2)) plot(clust,labels=F) hclustplot1(clust,colorh) } MakeVis = function(data,colorMod,vis.dir,pwr1,symbols){ q = table(colorMod) n = length(q) for(i in c(1:n)){ if(names(q[i]) != &#34;grey&#34;){ collect_garbage() newNet = pairwiseCode(data[,colorMod==names(q[i])],filename=paste(vis.dir,names(q[i]),&#34;.txt&#34;,sep=&#34;&#34;),pwr=pwr1,geneAnnot=symbols,this.col=names(q[i])) print(q[i]) if(!exists(&#34;newNetwork&#34;)){ newNetwork = newNet } else { newNetwork = rbind(newNetwork,newNet) } } } return(newNetwork) } MakePlots = function(data,colorMod,plots.dir){ PC = ModulePrinComps1(data,colorMod) q = table(colorMod) n = length(q) u = q &gt; 1 for(i in c(1:n)){ if(u[i]){ c = dimnames(PC[1])[2] indC = substr(c[i],3,25) filename = paste(plots.dir,indC,&#34;.png&#34;,sep=&#34;&#34;) png(filename) showHeat(indC,data,colorMod,PC) dev.off() print(paste(filename,&#34; printed to file&#34;)) }else{ indC = substr(c[i],3,25) print(paste(filename,&#34; only contains 1 gene&#34;)) } } } showHeat = function(color,data,colorh,PC){ q = table(colorh) z = names(q) == color Probe_sets = dimnames(data)[2] par(mfrow=c(2,1),mar=c(2,2,2,2)) par(mar=c(2,3,7,3)) par(oma=c(0,0,2,0)) datcombined=data.frame(rbind(data[,colorh==color])) samplelabel=as.character(dimnames(data)[1]) plot.mat(t(scale(datcombined)), rlabels=as.character(Probe_sets[colorh==color]), clabels=samplelabel, rcols=color) par(mar=c(2,2,0,2)) barplot(PC[1][,z],space=0,beside=TRUE,axes=FALSE,col=color) } ModulePrinComps1=function(datexpr,couleur) { modlevels=levels(factor(couleur)) PrinComps=data.frame(matrix(666,nrow=dim(datexpr)[1],ncol= length(modlevels))) varexplained= data.frame(matrix(666,nrow= 5,ncol= length(modlevels))) names(PrinComps)=paste(&#34;PC&#34;,modlevels,sep=&#34;&#34;) for(i in c(1:length(modlevels)) ){ print(i) modulename = modlevels[i] restrict1= as.character(couleur)== modulename in the following, rows are genes and columns are samples datModule=t(datexpr[, restrict1]) datModule=impute.knn(as.matrix(datModule)) datModule=t(scale(t(datModule))) svd1=svd(datModule) mtitle=paste(&#34;PCs of &#34;, modulename,&#34; module&#34;, sep=&#34;&#34;) varexplained[,i]= (svd1$d[1:5])2/sum(svd1$d2) this is the first principal component pc1=svd1$v[,1] signh1=sign(sum(co